CREATE Procedure [ADP].[ACCOUNT_PROJECT_SUMMARY_RAW] -- '2021-07-01','2021-07-04','Weekly'
(  
@startdate datetime,  
@endDate datetime,  
@mode varchar(200)  
)   
As

BEGIN

BEGIN TRY


IF EXISTS ( SELECT  top 1 1 FROM [CPCINCHPV004140].[AVMCOEESA].[DBO].[GMSPMO_Associate])

BEGIN

TRUNCATE TABLE [Adp].[CentralRepository_ActiveAllocations]

INSERT INTO [Adp].[CentralRepository_ActiveAllocations] (

[Associate_ID],
[Project_ID],
[Allocation_Start_Date],
[Allocation_End_Date],
[Allocation_Percentage],
[Location]	,
[Createddate],
[Created by]
)

SELECT 
[Associate_ID],
[Project_ID],
Assignmentstartdate,
Assignmentenddate,
Allocation_Percentage,
Assignment_Location	,
Getdate(),
'System'


from [CPCINCHPV004140].[AVMCOEESA].[DBO].[GMSPMO_Associate] 

END


END TRY

BEGIN CATCH      

DECLARE @ErrorMessage	NVARCHAR(4000);    
		DECLARE @ErrorSeverity	INT;    
		DECLARE @ErrorState		INT;  
		DECLARE @MailSubject	VARCHAR(MAX);		
		DECLARE @MailBody		VARCHAR(MAX);

		SELECT	@ErrorMessage	= ERROR_MESSAGE(),    
				@ErrorSeverity	= ERROR_SEVERITY(),    
				@ErrorState		= ERROR_STATE(); 

		SELECT @MailSubject = CONCAT(@@SERVERNAME, ': ADP ActiveAllocations Failure Notification')

		SELECT @MailBody = CONCAT('<font color="Black" face="Arial" Size = "2">Team, <br><br>Oops! Error Occurred in AdoptionReport GATEWAY CRS Refresh during the ADP Job Execution!<br>
				   <br>Error: ', @ErrorMessage,
				   '<br><br>Regards,<br>Applens Support Team<br><br>***Note: This is an auto generated mail. Please do not reply.***</font>')

				   DECLARE @recipientsAddress NVARCHAR(4000)='';
				   SET @recipientsAddress = (SELECT ConfigValue FROM [$(AppVisionLens)].AVL.AppLensConfig WHERE ConfigName='Mail' AND IsActive=1);   
				   EXEC msdb.dbo.sp_send_dbmail @recipients = @recipientsAddress,
				   @profile_name ='ApplensSupport',
				   @subject = @MailSubject,
				   @body = @MailBody,
				   @body_format = 'HTML';  

        ------------------------------------------------------	

END CATCH

END

