IF EXISTS ( SELECT TOP 1 1 FROM [CPCINCHPV004140].[AVMCOEESA].[dbo].[RHMSProjectManager])

BEGIN

MERGE  [ADP].[CentralRepository_Current_ProjectManager]  PM
    using [CPCINCHPV004140].[AVMCOEESA].[dbo].[RHMSProjectManager] CM (NOLOCK)
    ON PM.[PROJECT_ID] = CM.[PROJECT_ID] 
           WHEN matched THEN

 UPDATE SET PM.[PROJECT_ID] = CM.[PROJECT_ID]  ,
 PM.[PROJECT_MANAGER]=CM.[PROJECT_MANAGER],
PM.[LastUpdatedDatetime] = CM.[LastUpdatedDatetime],
PM.[Createddate] = getdate(),
PM.[Created by] = 'Sysytem'

WHEN NOT matched THEN 

INSERT  (

[PROJECT_ID],
[PROJECT_MANAGER],
[LastUpdatedDateTime],
[Createddate],
[Created by]
)

VALUES (

[PROJECT_ID],
[PROJECT_MANAGER],
[LastUpdatedDateTime],
Getdate (),
'System'


);


END


COMMIT TRAN

	END TRY

